SELECT president_id, birth_date
FROM biographies
ORDER BY birth_date ASC;

SELECT DISTINCT first_name || ' ' || last_name AS president_name
FROM presidents
ORDER BY president_name;

SELECT party_name
FROM political_parties
WHERE party_name = 'Federalist Party';

SELECT first_name || ' ' || last_name AS president_name
FROM presidents
ORDER BY president_id;

SELECT statement_date, statement_text
FROM public_statements
WHERE president_id = 1;

SELECT MIN(statement_date) AS earliest_statement, MAX(statement_date) AS latest_statement
FROM public_statements
WHERE president_id = 1;

SELECT COUNT(*) AS independent_presidents_count
FROM presidents
WHERE party_id IS NULL;

SELECT first_name, last_name
FROM vice_presidents
WHERE term_start <= '1797-03-04' AND term_end >= '1801-03-04';

SELECT COUNT(president_id) AS president_count
FROM party_affiliations
WHERE party_id = (SELECT party_id FROM political_parties WHERE party_name = 'Federalist');

SELECT COUNT(DISTINCT president_id) AS president_count
FROM party_affiliations
WHERE party_id = (SELECT party_id FROM political_parties WHERE party_name = 'Democratic Party');

SELECT first_name || ' ' || last_name AS full_name
FROM presidents
WHERE julianday(term_end) - julianday(term_start) = (
  SELECT MAX(julianday(term_end) - julianday(term_start))
  FROM presidents
);
